"use client";

import { Suspense, useEffect, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { useTableStore } from "@/stores/tableStore";
import { useOrderModeStore, OrderMode } from "@/stores/orderModeStore";
import { useCartStore } from "@/stores/cartStore";
import { getTableByNumber, PublicRestaurant } from "@/lib/api";
import { OrderModeSelector, RestaurantList } from "@/components/order";
import { Header } from "@/components/layout/Header";
import { BottomNav } from "@/components/layout/BottomNav";
import { Icon } from "@/components/ui/Icon";

function HomeContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const setTable = useTableStore((state) => state.setTable);
  const { mode, setMode, setRestaurant, clearMode } = useOrderModeStore();
  const { clearCart } = useCartStore();

  const [isQrMode, setIsQrMode] = useState<boolean | null>(null);

  useEffect(() => {
    const tableParam = searchParams.get("table");
    const menuParam = searchParams.get("menu");

    if (tableParam) {
      // QR code scan - set QR mode and redirect to menu
      setIsQrMode(true);
      setMode("qr");
      const tableNumber = parseInt(tableParam, 10);
      if (!isNaN(tableNumber)) {
        getTableByNumber(tableNumber)
          .then((table) => {
            setTable({
              id: table.id,
              number: table.number,
              restaurantId: table.restaurantId,
              restaurantName: table.restaurantName,
              menuId: menuParam || table.menuId,
              menuName: menuParam ? undefined : table.menuName,
              restaurantPhone: table.restaurantPhone,
              onlinePaymentAvailable: table.onlinePaymentAvailable,
            });
            router.replace("/menu");
          })
          .catch(() => {
            setTable({
              id: `table-${tableNumber}`,
              number: tableNumber,
              menuId: menuParam || undefined,
            });
            router.replace("/menu");
          });
        return;
      }
    }

    // No table param - show mode selection
    setIsQrMode(false);
  }, [searchParams, router, setTable, setMode]);

  const handleModeSelect = (selectedMode: OrderMode) => {
    setMode(selectedMode);
    // Clear cart when changing mode
    clearCart();
  };

  const handleSelectRestaurant = (restaurant: PublicRestaurant) => {
    setRestaurant(restaurant.id, restaurant.name, restaurant.deliveryFee);
    // Navigate to menu with restaurant context
    router.push(`/menu?restaurant=${restaurant.id}`);
  };

  // Loading state while checking for QR
  if (isQrMode === null) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-orange-50 to-white">
        <div className="animate-pulse flex flex-col items-center gap-4">
          <div className="w-20 h-20 rounded-full bg-gradient-to-br from-orange-400 to-orange-500 flex items-center justify-center shadow-lg shadow-orange-200">
            <Icon name="restaurant" size={40} className="text-white" />
          </div>
          <p className="text-gray-500 font-medium">Загрузка...</p>
        </div>
      </div>
    );
  }

  // QR mode loading
  if (isQrMode) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-orange-50 to-white">
        <div className="animate-pulse flex flex-col items-center gap-4">
          <div className="w-20 h-20 rounded-full bg-gradient-to-br from-orange-400 to-orange-500 flex items-center justify-center shadow-lg shadow-orange-200">
            <Icon name="qr_code_scanner" size={40} className="text-white" />
          </div>
          <p className="text-gray-500 font-medium">Загрузка меню...</p>
        </div>
      </div>
    );
  }

  // Mode selection UI with soft design
  return (
    <div className="min-h-screen bg-gradient-to-b from-orange-50 via-white to-orange-50/30 pb-20">
      {/* Decorative background elements */}
      <div className="absolute top-0 left-0 w-full h-64 overflow-hidden pointer-events-none">
        <div className="absolute -top-32 -left-32 w-64 h-64 bg-orange-200/30 rounded-full blur-3xl" />
        <div className="absolute -top-16 right-0 w-48 h-48 bg-amber-200/30 rounded-full blur-3xl" />
      </div>

      <Header title="QR Menu" />

      <div className="relative p-4 space-y-8 max-w-md mx-auto">
        {/* Welcome Hero */}
        <div className="text-center py-6">
          <div className="relative inline-block">
            <div className="w-24 h-24 rounded-3xl bg-gradient-to-br from-orange-400 to-orange-500 flex items-center justify-center shadow-xl shadow-orange-200/50 transform rotate-3">
              <Icon name="restaurant_menu" size={48} className="text-white" />
            </div>
            <div className="absolute -bottom-2 -right-2 w-8 h-8 rounded-full bg-gradient-to-br from-green-400 to-green-500 flex items-center justify-center shadow-lg">
              <Icon name="check" size={18} className="text-white" />
            </div>
          </div>
          <h1 className="text-3xl font-bold text-gray-800 mt-6 mb-2">
            Добро пожаловать!
          </h1>
          <p className="text-gray-500 text-lg">
            Выберите способ заказа
          </p>
        </div>

        {/* Mode selector */}
        <OrderModeSelector onModeSelect={handleModeSelect} />

        {/* Restaurant list */}
        {mode !== "qr" && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <RestaurantList
              mode={mode}
              onSelectRestaurant={handleSelectRestaurant}
            />
          </div>
        )}

        {/* QR hint card */}
        <div className="bg-white/80 backdrop-blur-sm rounded-2xl p-5 border border-gray-100 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-gray-100 to-gray-200 flex items-center justify-center">
              <Icon name="qr_code" size={24} className="text-gray-500" />
            </div>
            <div className="flex-1">
              <p className="font-semibold text-gray-800">
                Есть QR-код на столе?
              </p>
              <p className="text-sm text-gray-500">
                Отсканируйте его для быстрого заказа
              </p>
            </div>
            <Icon name="arrow_forward" size={20} className="text-gray-400" />
          </div>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}

export default function HomePage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-orange-50 to-white">
          <div className="animate-pulse flex flex-col items-center gap-4">
            <div className="w-20 h-20 rounded-full bg-gradient-to-br from-orange-400 to-orange-500 flex items-center justify-center shadow-lg shadow-orange-200">
              <Icon name="restaurant" size={40} className="text-white" />
            </div>
            <p className="text-gray-500 font-medium">Загрузка...</p>
          </div>
        </div>
      }
    >
      <HomeContent />
    </Suspense>
  );
}
